#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

vector<int> preorder_traversal(TreeNode* root) {
    if (!root) return {};
    vector<int> res = {root->val};
    auto left = preorder_traversal(root->left);
    auto right = preorder_traversal(root->right);
    res.insert(res.end(), left.begin(), left.end());
    res.insert(res.end(), right.begin(), right.end());
    return res;
}

vector<int> inorder_traversal(TreeNode* root) {
    if (!root) return {};
    auto left = preorder_traversal(root->left);
    auto right = preorder_traversal(root->right);
    left.push_back(root->val);
    left.insert(left.end(), right.begin(), right.end());
    return left;
}

vector<int> postorder_traversal(TreeNode* root) {
    if (!root) return {};
    auto left = preorder_traversal(root->left);
    auto right = preorder_traversal(root->right);
    left.insert(left.end(), right.begin(), right.end());
    left.push_back(root->val);
    return left;
}

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    TreeNode* root = new TreeNode(nums[0]);
    stack<TreeNode*> stack;
    stack.push(root);
    int i = 1;
    while (!stack.empty()) {
        TreeNode* node = stack.top();
        stack.pop();
        if (i < n) {
            node->left = new TreeNode(nums[i++]);
            stack.push(node->left);
        }
        if (i < n) {
            node->right = new TreeNode(nums[i++]);
            stack.push(node->right);
        }
    }
    auto preorder = preorder_traversal(root);
    auto inorder = inorder_traversal(root);
    auto postorder = postorder_traversal(root);
    for (auto& val : preorder) cout << val << ' ';
    cout << endl;
    for (auto& val : inorder) cout << val << ' ';
    cout << endl;
    for (auto& val : postorder) cout << val << ' ';
    cout << endl;
    return 0;
}
